"use client";

import { useEffect, useState } from "react";
import { api, type Ingredient } from "@/lib/api";
import { IngredientsCreate } from "./IngredientsCreate";

export default function IngredientsPage() {
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  function refresh() {
    setLoading(true);
    api
      .getIngredients()
      .then(setIngredients)
      .catch((e) => setError(e instanceof Error ? e.message : "Failed to load"))
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    refresh();
  }, []);

  return (
    <div className="mx-auto max-w-6xl px-4 py-6">
      <div className="mb-4 flex items-center justify-between">
        <h1 className="text-2xl font-semibold">Ingredients</h1>
        <IngredientsCreate onCreated={refresh} />
      </div>
      {loading && <p className="text-gray-500">Loading…</p>}
      {error && <p className="text-red-600">{error}</p>}
      {!loading && !error && (
        <div className="overflow-x-auto rounded border bg-white">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Name</th>
                <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Unit</th>
                <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Active</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {ingredients.map((ing) => (
                <tr key={ing.id} className="hover:bg-gray-50">
                  <td className="px-4 py-3 text-sm text-gray-900">{ing.name}</td>
                  <td className="px-4 py-3 text-sm text-gray-600">{ing.unitCode}</td>
                  <td className="px-4 py-3 text-sm">{ing.isActive ? "Yes" : "No"}</td>
                </tr>
              ))}
            </tbody>
          </table>
          {ingredients.length === 0 && (
            <p className="px-4 py-6 text-center text-gray-500">No ingredients yet.</p>
          )}
        </div>
      )}
    </div>
  );
}
